import{_ as a,c as r,o as i,a9 as s}from"./chunks/framework.CKUMok-g.js";const g=JSON.parse('{"title":"🚀 VitePress 插件开发计划","description":"主题在近1年多的时间里集成了非常的多功能了，接下来计划将这些能力拆分成组件，以便于更方便的与其它主题集成。","frontmatter":{"top":2,"sidebar":false,"description":"主题在近1年多的时间里集成了非常的多功能了，接下来计划将这些能力拆分成组件，以便于更方便的与其它主题集成。","head":[["script",{},"!function(p){\\"use strict\\";!function(t){var s=window,e=document,i=p,c=\\"\\".concat(\\"https:\\"===e.location.protocol?\\"https://\\":\\"http://\\",\\"sdk.51.la/js-sdk-pro.min.js\\"),n=e.createElement(\\"script\\"),r=e.getElementsByTagName(\\"script\\")[0];n.type=\\"text/javascript\\",n.setAttribute(\\"charset\\",\\"UTF-8\\"),n.async=!0,n.src=c,n.id=\\"LA_COLLECT\\",i.d=n;var o=function(){s.LA.ids.push(i)};s.LA?s.LA.ids&&o():(s.LA=p,s.LA.ids=[],o()),r.parentNode.insertBefore(n,r)}()}({\\"id\\":\\"Jgmg5avjAUvoyePS\\",\\"ck\\":\\"Jgmg5avjAUvoyePS\\",\\"hashMode\\":true});"]]},"headers":[],"relativePath":"essay/dev/vitepress-plugins.md","filePath":"essay/dev/vitepress-plugins.md","lastUpdated":1769670821000}'),t={name:"essay/dev/vitepress-plugins.md"};function l(n,e,p,o,h,d){return i(),r("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1769670821000"},[...e[0]||(e[0]=[s('<h1 id="🚀-vitepress-插件开发计划" tabindex="-1">🚀 VitePress 插件开发计划 <a class="header-anchor" href="#🚀-vitepress-插件开发计划" aria-label="Permalink to “🚀 VitePress 插件开发计划”">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to “前言”">​</a></h2><p>主题在近1年多的时间里集成了非常的多功能了，如 通知消息，公告，评论，图片预览，阅读时间分析 等等基础功能，有许多的用户反馈说能不能把这些能力独立成插件，以便于集成进现有的文档站中。</p><p>当然我自己也一直有这个想法，于是便有了这个文章来记录一下这个过程，同时抛出&amp;探讨一些问题。</p><h2 id="现有的一些问题" tabindex="-1">现有的一些问题 <a class="header-anchor" href="#现有的一些问题" aria-label="Permalink to “现有的一些问题”">​</a></h2><ol><li>生态缺少一个官方维护的 <a href="https://github.com/logicspark/awesome-vitepress-v1?tab=readme-ov-file" target="_blank" rel="noreferrer">awesome-vitepress</a> 来聚合 VitePress 相关的周边。</li><li>VitePress 本身并不提供插件机制去拓展各个部分，提供的是一套<a href="https://vitepress.dev/zh/guide/custom-theme" target="_blank" rel="noreferrer">主题方案</a>（重写布局+通用插槽），编写插件需按 Vite 的插件机制去实现。</li><li>主题有部分功能 和 element-ui 绑定在一起，拆分的时候部分需要考虑再手写一遍。</li></ol><h2 id="计划" tabindex="-1">计划 <a class="header-anchor" href="#计划" aria-label="Permalink to “计划”">​</a></h2><p>3 步走：</p><ol><li>摸索出 VitePress 在 Vite 的插件机制下提供的上下文，看看哪些口子可以用来做拓展。</li><li>以全局公告/文章评论/图片预览3个场景的插件的开发入手，整理出较通用的 VitePress 插件开发实践方案。</li><li>逐步拆分博客主题中的通用能力为独立插件。</li></ol><h2 id="已拆分插件" tabindex="-1">已拆分插件 <a class="header-anchor" href="#已拆分插件" aria-label="Permalink to “已拆分插件”">​</a></h2><h3 id="vitepress-plugin-pagefind" tabindex="-1"><a href="https://www.npmjs.com/package/vitepress-plugin-pagefind" target="_blank" rel="noreferrer">vitepress-plugin-pagefind</a> <a class="header-anchor" href="#vitepress-plugin-pagefind" aria-label="Permalink to “vitepress-plugin-pagefind”">​</a></h3><ul><li>基于 <a href="https://www.npmjs.com/package/pagefind" target="_blank" rel="noreferrer">pagefind</a> 提供离线化的全文搜索功能。</li></ul><h3 id="vitepress-plugin-rss" tabindex="-1"><a href="https://www.npmjs.com/package/vitepress-plugin-rss" target="_blank" rel="noreferrer">vitepress-plugin-rss</a> <a class="header-anchor" href="#vitepress-plugin-rss" aria-label="Permalink to “vitepress-plugin-rss”">​</a></h3><ul><li>基于 <a href="https://www.npmjs.com/package/feed" target="_blank" rel="noreferrer">feed</a> 提供 RSS 订阅链接生成功能。</li></ul><h3 id="vitepress-plugin-51la" tabindex="-1"><a href="https://www.npmjs.com/package/vitepress-plugin-51la" target="_blank" rel="noreferrer">vitepress-plugin-51la</a> <a class="header-anchor" href="#vitepress-plugin-51la" aria-label="Permalink to “vitepress-plugin-51la”">​</a></h3><ul><li>提供一键接入 <a href="https://v6.51.la/" target="_blank" rel="noreferrer">51.LA</a> 网站数据统计分析的功能。</li></ul><h3 id="vitepress-plugin-announcement" tabindex="-1"><a href="https://www.npmjs.com/package/vitepress-plugin-announcement" target="_blank" rel="noreferrer">vitepress-plugin-announcement</a> <a class="header-anchor" href="#vitepress-plugin-announcement" aria-label="Permalink to “vitepress-plugin-announcement”">​</a></h3><ul><li>提供全局公告窗口。</li></ul><h2 id="规划中的插件" tabindex="-1">规划中的插件 <a class="header-anchor" href="#规划中的插件" aria-label="Permalink to “规划中的插件”">​</a></h2><ul><li>评论</li><li>图片预览</li><li>标签页</li><li>文章时间轴</li><li>代码块折叠</li><li>OhMyLive2D</li><li>回到顶部</li><li>文章底部投币</li><li>短链</li><li>文章右下二维码分享</li><li>...</li></ul><h2 id="最后" tabindex="-1">最后 <a class="header-anchor" href="#最后" aria-label="Permalink to “最后”">​</a></h2><p>如果读者有其它建议或者想法可以私信或评论区交流。</p>',22)])])}const u=a(t,[["render",l]]);export{g as __pageData,u as default};
